func TestStateStore_Apply(t *testing.T) {
	s := NewStateStore("n1")
	entries := []*StateEntry{
		{Key: "k1", Value: []byte("v1"), Version: 1, NodeID: "n2"},
		{Key: "k2", Value: []byte("v2"), Version: 2, NodeID: "n2"},
	}
