func TestStateStore_PurgeTombstones(t *testing.T) {
	s := NewStateStore("n1")
	s.Put("k1", []byte("v1")) // version 1
	s.Delete("k1")            // version 2 (tombstone)
	s.Put("k2", []byte("v2")) // version 3

	purged := s.PurgeTombstones(2)
	if purged != 1 {
		t.Fatalf("expected 1 purged, got %d", purged)
	}
