func TestRing_FNV_Consistency(t *testing.T) {
	r := NewRing(150)
	r.Add("node-a")
	r.Add("node-b")
	r.Add("node-c")
	first := r.Lookup("test-key")
	for i := 0; i < 100; i++ {
