			t.Fatal("FNV hash should produce consistent results")
		}
	}
}

func TestRing_FNV_Distribution(t *testing.T) {
	r := NewRing(200)
	r.Add("n1")
	r.Add("n2")
	r.Add("n3")
	keys := make([]string, 10000)
	for i := range keys {
		keys[i] = fmt.Sprintf("dist-key-%d", i)
	}
	dist := r.Distribution(keys)
	for node, count := range dist {
		share := float64(count) / float64(len(keys))
		if share < 0.15 || share > 0.55 {
			t.Fatalf("node %s has %.2f share — FNV distribution too skewed", node, share)
		}
	}
}

func TestRing_TransferKeys_NoSideEffect(t *testing.T) {
	r := NewRing(100)
	r.Add("n1")
	r.Add("n2")
	sizeBefore := r.Size()

	keys := make([]string, 50)
	for i := range keys {
		keys[i] = fmt.Sprintf("tk-%d", i)
	}
	r.TransferKeys("n3", keys)

	if r.Size() != sizeBefore {
		t.Fatalf("TransferKeys should not modify ring: size was %d, now %d", sizeBefore, r.Size())
	}
	if r.HasNode("n3") {
		t.Fatal("TransferKeys should not permanently add the new node")
	}
}

func TestRing_FNV_MinimalDisruption(t *testing.T) {
	r := NewRing(100)
	r.Add("s1")
	r.Add("s2")
	keys := make([]string, 1000)
	for i := range keys {
		keys[i] = fmt.Sprintf("md-%d", i)
	}
	before := make(map[string]string, len(keys))
	for _, k := range keys {
		before[k] = r.Lookup(k)
	}
	r.Add("s3")
	moved := 0
	for _, k := range keys {
		if r.Lookup(k) != before[k] {
			moved++
		}
	}
	moveRate := float64(moved) / float64(len(keys))
	if moveRate > 0.60 {
		t.Fatalf("too many keys moved (%.2f) — minimal disruption violated", moveRate)
	}
}

