// Get retrieves a value by key. Returns nil, false if not found or tombstoned.
func (s *StateStore) Get(key string) ([]byte, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	e, ok := s.entries[key]
	if !ok || e.Tombstone {
		return nil, false
	}
	return copyBytes(e.Value), true
}

// GetRef retrieves a value by key without copying it.
// The returned slice aliases store-owned memory and must be treated as read-only.
// Returns nil, false if not found or tombstoned.
func (s *StateStore) GetRef(key string) ([]byte, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	e, ok := s.entries[key]
	if !ok || e.Tombstone {
		return nil, false
	}
	return e.Value, true
}

